import { useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import CartItem from '../components/Cart/CartItem';
import { formatPrice } from '../utils/formatters';
import Button from '../components/UI/Button';

const Cart = () => {
  const { items, updateQuantity, removeFromCart, clearCart, totalPrice } = useCart();
  const navigate = useNavigate();

  if (items.length === 0) {
    return (
      <div className="text-center py-16">
        <h2 className="text-2xl font-bold mb-4">السلة فارغة</h2>
        <p className="text-gray-600 mb-8">لم تقم بإضافة أي عناصر بعد</p>
        <Button onClick={() => navigate('/menu')} variant="primary">
          تصفح القائمة
        </Button>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto">
      <h1 className="text-3xl font-bold mb-8">سلة التسوق</h1>
      
      <div className="bg-white rounded-lg shadow-md p-6">
        {/* Cart items */}
        <div className="divide-y">
          {items.map((item, index) => (
            <CartItem
              key={`${item.menuItem}-${index}`}
              item={item}
              index={index}
              onUpdateQuantity={updateQuantity}
              onRemove={removeFromCart}
            />
          ))}
        </div>
        
        {/* Cart summary */}
        <div className="border-t mt-6 pt-6">
          <div className="flex justify-between items-center mb-4">
            <span className="text-lg font-medium">الإجمالي:</span>
            <span className="text-2xl font-bold text-primary-600">{formatPrice(totalPrice)}</span>
          </div>
          
          <div className="flex flex-col sm:flex-row gap-4">
            <Button
              onClick={clearCart}
              variant="secondary"
              className="sm:w-auto"
            >
              تفريغ السلة
            </Button>
            <Button
              onClick={() => navigate('/checkout')}
              variant="primary"
              className="flex-1 py-3"
            >
              متابعة الشراء
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Cart;
